import{_ as t,a as e,b as l,c as i,d as r,e as d,f as o,g as h}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as p,o as n,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"联盟分布索引使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/federated-distributed-index.md","filePath":"cn/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),b={name:"cn/Other/federated-distributed-index.md"};function u(m,a,q,_,f,x){return n(),s("div",null,[...a[0]||(a[0]=[c('<h1 id="联盟分布索引使用说明" tabindex="-1">联盟分布索引使用说明 <a class="header-anchor" href="#联盟分布索引使用说明" aria-label="Permalink to &quot;联盟分布索引使用说明&quot;">​</a></h1><p>联盟分布索引用来让多个图床站点互相共享文件列表。</p><p>简单理解：</p><ul><li>你可以把自己的某些文件夹共享给别人。</li><li>你也可以加入别人的节点，把对方共享的文件列表同步到自己的后台里查看。</li><li>联盟文件主要用于浏览、搜索和访问，不是在本机重新上传一份文件。</li></ul><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><p>联盟分布索引在：</p><p>系统配置 -&gt; 其他设置 -&gt; 联盟分布索引</p><p><img src="'+t+`" alt="联盟分布索引本地节点" loading="lazy"></p><p>页面分成三个页签：</p><table tabindex="0"><thead><tr><th>页签</th><th>用途</th></tr></thead><tbody><tr><td>本地节点</td><td>设置自己的联盟开关、对外域名、共享文件夹，并更新索引</td></tr><tr><td>我加入的节点</td><td>管理自己加入的其他图床节点</td></tr><tr><td>加入我的节点</td><td>管理别人申请加入你的节点</td></tr></tbody></table><h2 id="第一次使用怎么设置" tabindex="-1">第一次使用怎么设置 <a class="header-anchor" href="#第一次使用怎么设置" aria-label="Permalink to &quot;第一次使用怎么设置&quot;">​</a></h2><ol><li>打开“本地节点”。</li><li>打开“启用”开关。</li><li>在“同步文件夹”里选择要共享出去的文件夹。</li><li>点击“更新出站索引”。</li><li>如果系统提示检测到域名变化，确认当前域名没问题后继续。</li></ol><p>同步文件夹可以选多个。</p><p>如果同步文件夹清空，表示共享全部文件夹。</p><h2 id="本地节点怎么用" tabindex="-1">本地节点怎么用 <a class="header-anchor" href="#本地节点怎么用" aria-label="Permalink to &quot;本地节点怎么用&quot;">​</a></h2><h3 id="对外域名" tabindex="-1">对外域名 <a class="header-anchor" href="#对外域名" aria-label="Permalink to &quot;对外域名&quot;">​</a></h3><p>对外域名是别人访问你这个节点时使用的站点地址。</p><p>这个地址由系统自动识别，不需要手动填写。第一次更新索引时，系统会让你确认当前访问地址是不是正式域名。</p><p>如果以后换了域名，再点更新索引时也会提示确认。</p><h3 id="同步文件夹" tabindex="-1">同步文件夹 <a class="header-anchor" href="#同步文件夹" aria-label="Permalink to &quot;同步文件夹&quot;">​</a></h3><p>同步文件夹决定哪些文件会共享给联盟节点。</p><p>例如你只选择：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>别人同步你的节点时，就只能看到这两个目录里的文件。</p><h3 id="更新出站索引" tabindex="-1">更新出站索引 <a class="header-anchor" href="#更新出站索引" aria-label="Permalink to &quot;更新出站索引&quot;">​</a></h3><p>这个按钮用于更新“我共享给别人看的文件列表”。</p><p>适合在这些时候点击：</p><ul><li>第一次启用联盟。</li><li>新上传了一批想共享的文件。</li><li>改了同步文件夹。</li><li>换了对外域名后需要确认新域名。</li></ul><h2 id="我加入的节点怎么用" tabindex="-1">我加入的节点怎么用 <a class="header-anchor" href="#我加入的节点怎么用" aria-label="Permalink to &quot;我加入的节点怎么用&quot;">​</a></h2><p>“我加入的节点”是你订阅别人的地方。</p><p><img src="`+e+'" alt="我加入的节点" loading="lazy"></p><h3 id="申请加入别人" tabindex="-1">申请加入别人 <a class="header-anchor" href="#申请加入别人" aria-label="Permalink to &quot;申请加入别人&quot;">​</a></h3><ol><li>找对方要一条邀请链接。</li><li>粘贴到输入框。</li><li>点击“申请加入”。</li><li>等对方在自己的后台同意。</li></ol><p>对方同意后，这条节点会变成“已同意”。</p><h3 id="更新入站索引" tabindex="-1">更新入站索引 <a class="header-anchor" href="#更新入站索引" aria-label="Permalink to &quot;更新入站索引&quot;">​</a></h3><p>更新入站索引用来把你已加入节点的文件列表同步到本机。</p><p>适合在这些时候点击：</p><ul><li>对方刚同意你的申请后。</li><li>对方告诉你他更新了共享内容。</li><li>你想刷新全部已加入节点的联盟文件列表。</li></ul><p>如果只想更新某一个节点，可以在对应节点卡片上点“更新索引”。</p><p><img src="'+l+'" alt="更新索引" loading="lazy"></p><h3 id="取消订阅" tabindex="-1">取消订阅 <a class="header-anchor" href="#取消订阅" aria-label="Permalink to &quot;取消订阅&quot;">​</a></h3><p>如果不想继续同步某个节点，可以点击“取消订阅”。</p><p>取消后，这个节点的联盟索引也会从本机清理掉。</p><h2 id="加入我的节点怎么用" tabindex="-1">加入我的节点怎么用 <a class="header-anchor" href="#加入我的节点怎么用" aria-label="Permalink to &quot;加入我的节点怎么用&quot;">​</a></h2><p>“加入我的节点”是别人申请加入你的地方。</p><p><img src="'+i+'" alt="加入我的节点" loading="lazy"></p><h3 id="生成邀请链接" tabindex="-1">生成邀请链接 <a class="header-anchor" href="#生成邀请链接" aria-label="Permalink to &quot;生成邀请链接&quot;">​</a></h3><ol><li>先确认本地节点已经启用。</li><li>先点过“更新出站索引”，让系统确认过对外域名。</li><li>打开“加入我的节点”。</li><li>点击“重置邀请链接”。</li><li>复制邀请链接发给对方。</li></ol><p>如果邀请链接为空，通常是还没有确认对外域名。回到“本地节点”点一次“更新出站索引”即可。</p><h3 id="处理加入申请" tabindex="-1">处理加入申请 <a class="header-anchor" href="#处理加入申请" aria-label="Permalink to &quot;处理加入申请&quot;">​</a></h3><p>别人提交申请后，会出现在“加入我的节点”列表里。</p><table tabindex="0"><thead><tr><th>操作</th><th>作用</th></tr></thead><tbody><tr><td>同意</td><td>允许对方同步你共享的文件列表</td></tr><tr><td>拒绝</td><td>不允许对方加入</td></tr><tr><td>删除</td><td>删除已经结束的记录</td></tr><tr><td>检查状态</td><td>检查对方是否还保留这段关系</td></tr></tbody></table><p>同意之后，对方还需要在自己那边点“更新入站索引”，才能看到你共享的文件列表。</p><p><img src="'+r+'" alt="邀请节点同意" loading="lazy"></p><h2 id="留言功能" tabindex="-1">留言功能 <a class="header-anchor" href="#留言功能" aria-label="Permalink to &quot;留言功能&quot;">​</a></h2><p>关系已经同意后，可以在节点卡片里点“留言”。</p><p>留言只用于联盟关系沟通，不会影响文件、标签、目录和访问权限。</p><p><img src="'+d+'" alt="留言功能" loading="lazy"></p><h2 id="在哪里看联盟文件" tabindex="-1">在哪里看联盟文件 <a class="header-anchor" href="#在哪里看联盟文件" aria-label="Permalink to &quot;在哪里看联盟文件&quot;">​</a></h2><p>同步完成后，回到管理后台文件列表。</p><p>页面顶部可以在本地文件和联盟文件之间切换。切到联盟文件后，就能浏览已同步的联盟内容。</p><p>联盟文件主要用于查看、搜索、预览和复制链接。它不是本机文件，所以不能在本机直接移动、删除、改标签或备份。</p><p><img src="'+o+'" alt="联盟管理显示效果图" loading="lazy"></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么有无关系记录重新申请" tabindex="-1">为什么有无关系记录重新申请？ <a class="header-anchor" href="#为什么有无关系记录重新申请" aria-label="Permalink to &quot;为什么有无关系记录重新申请？&quot;">​</a></h3><p>一般是对方把你删除并删除记录，导致查询不到你的这段记录显示无关系记录，需要你重新申请关系</p><p><img src="'+h+'" alt="无关系记录重新申请" loading="lazy"></p><h3 id="为什么加入后看不到文件" tabindex="-1">为什么加入后看不到文件？ <a class="header-anchor" href="#为什么加入后看不到文件" aria-label="Permalink to &quot;为什么加入后看不到文件？&quot;">​</a></h3><p>先确认这几件事：</p><ol><li>对方已经同意你的申请。</li><li>对方已经点过“更新出站索引”。</li><li>你自己已经点过“更新入站索引”。</li><li>对方的同步文件夹里确实包含要共享的目录。</li></ol><h3 id="提示域名变化怎么办" tabindex="-1">提示域名变化怎么办？ <a class="header-anchor" href="#提示域名变化怎么办" aria-label="Permalink to &quot;提示域名变化怎么办？&quot;">​</a></h3><p>如果你现在打开后台用的就是正式域名，可以确认继续。</p><p>如果你只是临时用其他地址访问后台，建议取消，换成正式域名重新打开后台再操作。</p><h3 id="同步文件夹清空是什么意思" tabindex="-1">同步文件夹清空是什么意思？ <a class="header-anchor" href="#同步文件夹清空是什么意思" aria-label="Permalink to &quot;同步文件夹清空是什么意思？&quot;">​</a></h3><p>同步文件夹清空表示共享全部文件夹。</p><p>如果只想共享一部分目录，就手动选择对应文件夹。</p><h3 id="更新出站和更新入站有什么区别" tabindex="-1">更新出站和更新入站有什么区别？ <a class="header-anchor" href="#更新出站和更新入站有什么区别" aria-label="Permalink to &quot;更新出站和更新入站有什么区别？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>简单理解</th></tr></thead><tbody><tr><td>更新出站索引</td><td>更新“别人能从我这里同步到什么”</td></tr><tr><td>更新入站索引</td><td>更新“我从别人那里同步到了什么”</td></tr></tbody></table>',78)])])}const y=p(b,[["render",u]]);export{P as __pageData,y as default};
